(@mobile_mod2, 'Hooks e State Management', 'useState, useEffect e Context API',
'<h2>Hooks em React Native</h2>
<h3>useState</h3>
<pre><code>import { useState } from "react";
import { View, Text, Button } from "react-native";

export default function Counter() {
  const [count, setCount] = useState(0);

  return (
    <View>
      <Text>Contagem: {count}</Text>
      <Button title="Incrementar" onPress={() => setCount(count + 1)} />
    </View>
  );
}</code></pre>
<h3>useEffect</h3>
<pre><code>import { useEffect, useState } from "react";

export default function DataFetcher() {
  const [data, setData] = useState(null);

  useEffect(() => {
    fetch("https://api.example.com/data")
      .then(res => res.json())
      .then(data => setData(data));
  }, []); // Executa apenas uma vez

  return <Text>{data ? JSON.stringify(data) : "Carregando..."}</Text>;
}</code></pre>
<h3>Context API para State Global</h3>
<pre><code>import { createContext, useContext, useState } from "react";

const ThemeContext = createContext();

export function ThemeProvider({ children }) {
  const [isDark, setIsDark] = useState(false);
  return (
    <ThemeContext.Provider value={{ isDark, setIsDark }}>
      {children}
    </ThemeContext.Provider>
  );
}

export function useTheme() {
  return useContext(ThemeContext);
}</code></pre>',
'[{"id": 1, "title": "Qual hook é usado para efeitos colaterais em React Native?", "type": "multiple_choice", "options": ["useState", "useEffect", "useContext", "useReducer"], "correct": 1}]', 3);

