(@mobile_mod3, 'State Management em Flutter', 'StatefulWidget e Provider',
'<h2>State Management em Flutter</h2>
<h3>StatefulWidget</h3>
<pre><code>class Counter extends StatefulWidget {
  @override
  State<Counter> createState() => _CounterState();
}

class _CounterState extends State<Counter> {
  int count = 0;

  @override
  Widget build(BuildContext context) {
    return Column(
      children: [
        Text("Contagem: $count", style: TextStyle(fontSize: 24)),
        ElevatedButton(
          onPressed: () {
            setState(() {
              count++;
            });
          },
          child: Text("Incrementar"),
        ),
      ],
    );
  }
}</code></pre>
<h3>Provider Package</h3>
<pre><code>// Definir um ChangeNotifier
class CounterProvider extends ChangeNotifier {
  int _count = 0;

  int get count => _count;

  void increment() {
    _count++;
    notifyListeners();
  }
}

// Usar no widget
class MyApp extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    return ChangeNotifierProvider(
      create: (context) => CounterProvider(),
      child: Consumer<CounterProvider>(
        builder: (context, provider, child) {
          return Text("Contagem: ${provider.count}");
        },
      ),
    );
  }
}</code></pre>
